import{_ as a,o as r,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse(`{"title":"15. Allowances","description":"","frontmatter":{"title":"15. Allowances","eba":"Children's Services Award 2010","topics":["hours","overtime","shift-work","allowances"]},"headers":[],"relativePath":"ebas/childrens-services/wages/15-allowances.md","filePath":"ebas/childrens-services/wages/15-allowances.md"}`),l={name:"ebas/childrens-services/wages/15-allowances.md"};function s(i,e,n,c,p,d){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_15-allowances" tabindex="-1">15. Allowances <a class="header-anchor" href="#_15-allowances" aria-label="Permalink to &quot;15. Allowances&quot;">​</a></h1><p>To view the current monetary amounts of work-related allowances refer to the <a href="https://www.fwc.gov.au/documents/awards/resources/ma000120-all.pdf" target="_blank" rel="noreferrer">Allowances Sheet</a>.</p><ol><li>Broken shift allowance</li></ol><blockquote><p>Where an employee works two separate shifts in a day, they will be paid an allowance of 1.91% of the <a href="#standard_rate">standard rate</a> per day for each day on which a broken shift is worked.</p></blockquote><ol><li><p>Clothing and equipment allowance</p><p>a. Where the employer requires an employee to wear any special clothing or articles of clothing the employer must reimburse the employee for the cost of purchasing such clothing. The provisions of this clause do not apply where the employer pays for the clothing required to be worn by the employee.</p><p>b. Where an employee is required to launder any clothing referred to in clause 15.2(a) the employee will be paid an allowance of \\9.49 per week or \\1.90 per day, or where the uniform does not require ironing, \\5.98 per week or \\1.20 per day.</p></li></ol><p>[15.2(c) substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723626.htm" target="_blank" rel="noreferrer">PR723626</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR724049.htm" target="_blank" rel="noreferrer">PR724049</a> ppc 01Nov20]</p><p>c. Where an employee is required to wear protective clothing or equipment such as hats and sunscreen lotion, goggles, aprons or gloves, the employer will either supply such clothing or equipment or reimburse the employee for the cost of their purchase. Reimbursement will be limited to reasonable costs incurred.</p><ol><li>Excess fares allowance</li></ol><blockquote><p>Where an employee is directed to work away from their normal place of work on any day the employee will be paid an allowance of \\16.86 per day to compensate for excess fares. This provision does not apply if the employer provides or offers to provide suitable transport free of charge to the employee.</p></blockquote><ol><li>First aid allowance</li></ol><p>[15.4(a) varied by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR996603.htm" target="_blank" rel="noreferrer">PR996603</a> ppc 28Apr10]</p><p>a. Where an employee classified below Level 3 is required by the employer to administer first aid to children within the employee&#39;s care and the employee holds a current recognised first aid qualification such as a certificate from the St John Ambulance, the Australian Red Cross or a similar body they will be paid an allowance of 1.13% of the <a href="#standard_rate">standard rate</a> per day. Where the employee is employed in out-of-school hours care, the allowance will be 0.15% of the <a href="#standard_rate">standard rate</a> per hour.</p><p>b. Provided that a first aid officer need not be appointed where a qualified nurse is on the premises at all times.</p><p>c. Where an employee is required by an employer to act as a first aid officer and they do not have current qualifications, the employer must pay the costs of any required training.</p><ol><li>Meal allowance</li></ol><p>An employee required to work overtime for more than two hours without being notified on the previous day or earlier that they will be so required to work will either be supplied with a meal by the employer or paid an allowance of \\15.48. No meal allowance is payable where an employee could reasonably return home for a meal within the period allowed.</p><ol><li>Qualifications allowance</li></ol><p>A Director or Assistant Director who holds a Graduate Certificate in Childcare Management or equivalent will be paid an all-purpose allowance, calculated at 5% of the weekly rate for an Assistant Director (Children&#39;s Services Employee Level 5.4).</p><ol><li>Use of vehicle allowance</li></ol><p>Where an employer requests an employee to use their own motor vehicle in the performance of their duties the employee will be paid an allowance of \\0.99 per kilometre in the case of a motor car or \\0.33 per kilometre in the case of a motorcycle.</p><ol><li>Educational leader allowance</li></ol><p>[15.8(a) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr762229.pdf" target="_blank" rel="noreferrer">PR762229</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr774011.pdf" target="_blank" rel="noreferrer">PR774011</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr786659.pdf" target="_blank" rel="noreferrer">PR786659</a> ppc 01Jul25]</p><p>a. An educational leader&#39;s allowance of \\4567.31 per annum will be paid to an employee who is required to discharge the responsibilities of the educational leader under Regulation 118 of the <em>Education and Care Services National Regulations 2011</em>.</p><p>b. Where an employee is required to act as educational leader for less than 5 days per week, the annual allowance prescribed by clause 15.8(a) will be payable on a pro rata basis calculated by reference to the number of days per week the employee is required to act as educational leader.</p><p>NOTE: The allowance prescribed in clause 15.8(a) is the same amount as the educational leader allowance prescribed by <a href="/eba/ebas/childrens-services/wages/19-payment-of-wages.html">clause 19</a>.4 of the <em>Educational Services (Teachers) Award 2020</em> and will be adjusted each year to reflect the amount set in the <em>Educational Services (Teachers) Award 2020.</em></p><ol><li>Adjustment of expense related allowances</li></ol><p>a. At the time of any adjustment to the <a href="#standard_rate">standard rate</a>, each expense related allowance will be increased by the relevant adjustment factor. The relevant adjustment factor for this purpose is the percentage movement in the applicable index figure most recently published by the Australian Bureau of Statistics since the allowance was last adjusted.</p><p>[15.8(b) varied by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR523102.htm" target="_blank" rel="noreferrer">PR523102</a> ppc 01Jul12]</p><p>b. The applicable index figure is the index figure published by the Australian Bureau of Statistics for the Eight Capitals Consumer Price Index (Cat No. 6401.0), as follows:</p><p><strong>Allowance</strong> <strong>Applicable Consumer Price Index figure</strong></p><hr><p>Clothing and equipment allowance Clothing and footwear group Excess fares allowance Transport group Meal allowance Take away and fast foods sub-group Vehicle allowance Private motoring sub-group</p><p>Plain language terms: award allowances.</p>',33)])])}const w=a(l,[["render",s]]);export{u as __pageData,w as default};
